import pg from "pg";
import crypto from "crypto";
const Pool = pg.Pool;
const pool = new Pool({ connectionString: process.env.PROD_DATABASE_URL || process.env.DATABASE_URL });
function hash(s: string): string { return crypto.createHash("md5").update(s.toLowerCase().trim()).digest("hex"); }

interface Q {
  tier: string; exam: string; stem: string; options: string[];
  correct: number; rationale: string; diff: number; bs: string;
  topic: string; subtopic: string; tags: string[]; clinicalPearl: string;
}

function q(bs: string, d: number, s: string, o: string[], c: number, r: string, topic: string, subtopic: string, tags: string[], pearl: string): Q {
  return { tier: "rn", exam: "NCLEX-RN", stem: s, options: o, correct: c, rationale: r, diff: d, bs, topic, subtopic, tags, clinicalPearl: pearl };
}

const QS: Q[] = [
  // ============================================================
  // CARDIAC (15)
  // ============================================================
  q("Cardiovascular", 3, "A nurse is caring for a client who received a tissue (bioprosthetic) heart valve. The nurse should teach that compared to mechanical valves:", ["Tissue valves require lifelong anticoagulation with warfarin", "Tissue valves generally do not require long-term anticoagulation but may need replacement in 10-20 years due to structural deterioration", "Tissue valves last longer than mechanical valves", "There is no functional difference"], 1, "Tissue (bioprosthetic) valves from porcine or bovine pericardium have lower thrombogenicity and typically require anticoagulation only for the first 3-6 months, then aspirin alone. However, they have limited durability (10-20 years) and may require reoperation. Mechanical valves require lifelong warfarin but last longer. Choice depends on age, lifestyle, and ability to manage anticoagulation. Option A describes mechanical valves. Options C and D are incorrect.", "Valvular Heart Disease", "Valve Types Comparison", ["cardiac", "valve-replacement", "tissue-valve", "anticoagulation"], "Tissue vs mechanical valve: Tissue = short-term anticoagulation, limited lifespan (10-20 yrs), preferred in elderly/pregnancy planners. Mechanical = lifelong warfarin (INR 2.5-3.5), durable, preferred in younger patients."),

  q("Cardiovascular", 2, "A nurse identifies ST-segment elevation in leads II, III, and aVF on the ECG. This indicates an acute MI in which area?", ["Anterior wall", "Inferior wall of the heart", "Lateral wall", "Septal wall"], 1, "ECG lead localization: leads II, III, aVF = inferior wall (right coronary artery territory). Leads V1-V4 = anterior wall (LAD territory). Leads I, aVL, V5-V6 = lateral wall (circumflex territory). Leads V1-V2 = septal wall. This knowledge helps predict complications: inferior MI may cause bradycardia and heart block (RCA supplies the SA and AV nodes). Option A would show ST elevation in V1-V4. Options C and D involve different lead groups.", "Acute Coronary Syndrome", "ECG Localization", ["cardiac", "STEMI", "ECG", "inferior-MI"], "ECG MI localization: Inferior = II, III, aVF (RCA). Anterior = V1-V4 (LAD). Lateral = I, aVL, V5-V6 (LCx). Right ventricular = V4R. Inferior MI: watch for bradycardia, heart block. Anterior MI: watch for CHF, cardiogenic shock."),

  q("Cardiovascular", 3, "A client with an implantable cardioverter-defibrillator (ICD) receives a shock. The nurse should assess:", ["Only document the event", "The client's rhythm, hemodynamic status, and consciousness; if the client is stable, notify the cardiologist; if unstable, initiate ACLS", "Remove the ICD immediately", "Ignore the shock as this is normal function"], 1, "After an ICD shock, the nurse should: 1) Assess the client's rhythm and hemodynamic stability, 2) Document the event (time, activity, preceding symptoms), 3) Evaluate for appropriate vs inappropriate shock, 4) Notify the cardiologist for device interrogation, 5) If multiple shocks (electrical storm), provide ACLS care and IV amiodarone. The client may be anxious — provide emotional support. Options A and D are incomplete. Option C is never appropriate.", "ICD Management", "Post-Shock Assessment", ["cardiac", "ICD", "shock", "assessment"], "Post-ICD shock: assess rhythm, stability, consciousness. Single appropriate shock: notify cardiology for interrogation. Electrical storm (3+ shocks in 24 hrs): ACLS, IV amiodarone, sedate if conscious. Inappropriate shocks: device malfunction or lead fracture needs urgent evaluation."),

  q("Cardiovascular", 3, "A client with peripheral arterial disease reports claudication that occurs after walking 2 blocks. The nurse should teach:", ["Stop all walking and rest indefinitely", "Walk until pain occurs, rest until pain subsides, then resume walking to build collateral circulation", "Apply heating pads to the legs", "Elevate the legs above the heart at all times"], 1, "Exercise therapy for PAD: structured walking programs build collateral circulation and increase pain-free walking distance. Walk until moderate claudication pain occurs, rest until resolved, then resume. Goal: 30-60 minutes, 3-5 times per week. Also: smoking cessation (#1 modifiable risk factor), foot care, statin therapy, antiplatelet agent. Option A leads to deconditioning. Option C can cause burns (impaired sensation). Option D reduces arterial flow.", "Peripheral Arterial Disease", "Exercise Therapy", ["cardiac", "PAD", "claudication", "exercise"], "PAD management: #1 = smoking cessation. Supervised exercise training improves walking distance. Position: legs flat or slightly dependent (not elevated like venous disease). Foot care essential (poor healing)."),

  q("Cardiovascular", 4, "A nurse is caring for a client in cardiogenic shock with IABP support. The nurse notes the balloon is not deflating properly (late deflation). This will result in:", ["Improved cardiac output", "Increased afterload during systole because the balloon remains inflated when the ventricle is trying to eject, increasing myocardial oxygen demand", "No hemodynamic consequence", "Improved coronary perfusion"], 1, "Late IABP deflation means the balloon is still partially inflated when systole begins. The ventricle must eject against the still-inflated balloon, increasing afterload and myocardial oxygen demand. Early inflation improves coronary perfusion (desired). Late inflation misses the opportunity for coronary perfusion augmentation. Early deflation reduces afterload assistance. Proper timing is critical. Options A, C, and D are incorrect.", "IABP", "Timing Errors", ["cardiac", "IABP", "timing", "critical-care"], "IABP timing errors: Early inflation = closes aortic valve prematurely (reduces SV). Late inflation = missed coronary perfusion augmentation. Early deflation = suboptimal afterload reduction. Late deflation = increased afterload (worst error)."),

  // ============================================================
  // RESPIRATORY (10)
  // ============================================================
  q("Respiratory", 3, "A client intubated on mechanical ventilation develops auto-PEEP (breath stacking). The nurse should anticipate:", ["Increasing the respiratory rate", "Increasing expiratory time by reducing respiratory rate or adjusting I:E ratio", "Removing the endotracheal tube", "Adding more PEEP"], 1, "Auto-PEEP (intrinsic PEEP) occurs when the patient cannot fully exhale before the next breath, causing air trapping. Common in COPD and asthma. Treatment: increase expiratory time by decreasing respiratory rate, reducing tidal volume, or adjusting I:E ratio (1:3 or higher). Also: bronchodilators to reduce airway obstruction, and ensure adequate ETT patency. Option A worsens auto-PEEP. Option C is extreme. Option D may worsen (though sometimes low-level extrinsic PEEP helps).", "Mechanical Ventilation", "Auto-PEEP Management", ["respiratory", "auto-PEEP", "ventilation", "COPD"], "Auto-PEEP: air trapping from incomplete exhalation. Causes: high RR, bronchospasm, small ETT. Detection: end-expiratory flow does not reach zero. Effects: hemodynamic compromise (increased intrathoracic pressure). Treatment: increase expiratory time, bronchodilators."),

  q("Respiratory", 2, "A client with COPD is prescribed a combination inhaler containing fluticasone/salmeterol (Advair). The nurse should teach:", ["Use this as a rescue inhaler for acute shortness of breath", "Rinse the mouth after each use to prevent oral candidiasis from the inhaled corticosteroid component", "Shake the Diskus device before use", "Only use during acute exacerbations"], 1, "Fluticasone (ICS) + salmeterol (LABA) is a maintenance inhaler, NOT for acute rescue. Oral rinsing after each use is essential to prevent oral candidiasis (thrush) and hoarseness from the ICS component. Advair Diskus is a DPI — do NOT shake (unlike MDIs). Use twice daily as prescribed, regardless of symptoms. Option A is dangerous (LABA alone can worsen asthma). Option C is incorrect for DPI. Option D misses the maintenance purpose.", "COPD Medications", "Combination Inhaler", ["respiratory", "ICS-LABA", "oral-care", "COPD"], "ICS teaching: rinse mouth after EVERY use (prevents thrush). LABA: never use alone in asthma (FDA black box). Combination ICS/LABA: maintenance only, not rescue. DPI: don't shake, quick deep breath. MDI: shake, slow deep breath."),

  q("Respiratory", 3, "A client with a tracheostomy experiences accidental decannulation. The nurse should:", ["Wait for the physician to arrive", "Keep the stoma open with a tracheal dilator or hemostat, and reinsert the tracheostomy tube or insert an ETT through the stoma", "Cover the stoma and ventilate via the mouth", "Apply pressure to the stoma to close it"], 1, "Accidental tracheostomy decannulation is an emergency, especially for fresh tracheostomies (<7 days). Immediate actions: call for help, keep the stoma open (tracheal dilator or hemostat), attempt to reinsert the same or one-size-smaller tracheostomy tube, or insert an ETT through the stoma if the tracheostomy tube is unavailable. If unable to recanulate: BMV through the stoma (cover mouth/nose) or through the mouth/nose (cover stoma). Have an obturator at the bedside. Options A and D delay critical intervention. Option C is incomplete.", "Tracheostomy", "Emergency Decannulation", ["respiratory", "tracheostomy", "decannulation", "emergency"], "Tracheostomy emergency supplies at bedside: extra tracheostomy tube (same size + one size smaller), obturator, tracheal dilator/hemostat, suction equipment, BMV. Fresh trach (<7 days): stoma can close rapidly. Mature trach (>7 days): stoma is more established."),

  // ============================================================
  // GI (8)
  // ============================================================
  q("Gastrointestinal", 3, "A nurse is assessing a client with ascites secondary to cirrhosis. The nurse measures abdominal girth to:", ["Determine body fat percentage", "Monitor fluid accumulation in the peritoneal cavity; increasing girth indicates worsening ascites", "Assess for bowel obstruction", "Calculate medication dosing"], 1, "Abdominal girth measurement tracks changes in ascites volume over time. Technique: mark the measurement location at the umbilicus level on the abdomen, use the same position (supine), measure at the same time daily, and record the measurement. Increasing girth indicates worsening ascites requiring treatment intensification (sodium restriction, diuretics, paracentesis). Option A is not the purpose. Options C and D are incorrect uses.", "Cirrhosis", "Ascites Monitoring", ["GI", "cirrhosis", "ascites", "assessment"], "Ascites monitoring: daily abdominal girth (mark measurement site), daily weights, I&O, sodium restriction (<2g/day), diuretics (spironolactone + furosemide). Paracentesis for tense ascites. TIPS for refractory ascites."),

  q("Gastrointestinal", 2, "A client with a history of peptic ulcer disease tests positive for Helicobacter pylori. The nurse anticipates which treatment regimen?", ["Antacids alone", "Triple therapy: PPI + clarithromycin + amoxicillin (or metronidazole) for 14 days", "Surgical intervention as first-line treatment", "H2 blockers alone for 4 weeks"], 1, "H. pylori eradication: standard triple therapy for 14 days (PPI BID + clarithromycin 500mg BID + amoxicillin 1g BID). If penicillin allergy: substitute metronidazole for amoxicillin. Bismuth quadruple therapy is an alternative (PPI + bismuth + metronidazole + tetracycline). Confirm eradication 4-6 weeks after treatment with urea breath test or stool antigen. Option A is insufficient. Options C and D are not first-line.", "Peptic Ulcer Disease", "H. pylori Eradication", ["GI", "H-pylori", "triple-therapy", "PUD"], "H. pylori treatment: triple therapy x 14 days. Confirm eradication 4+ weeks after completing treatment (urea breath test or stool antigen). Do NOT use antibody test for confirmation (stays positive after eradication). H. pylori causes ~80% of duodenal ulcers and ~60% of gastric ulcers."),

  q("Gastrointestinal", 3, "A client is prescribed lactulose for hepatic encephalopathy. The nurse should titrate the dose to achieve:", ["One bowel movement per week", "Two to three soft bowel movements per day", "Watery diarrhea continuously", "No bowel movements"], 1, "Lactulose is an osmotic laxative that draws ammonia into the bowel lumen (converting NH3 to NH4+ which cannot be reabsorbed) and promotes excretion through stool. Goal: 2-3 soft bowel movements per day. Too few = inadequate ammonia clearance. Excessive diarrhea = dehydration and electrolyte imbalances. Also monitor: mental status, ammonia levels, and electrolytes. Option A is inadequate. Option C causes complications. Option D defeats the purpose.", "Hepatic Encephalopathy", "Lactulose Titration", ["GI", "lactulose", "hepatic-encephalopathy", "ammonia"], "Lactulose dosing: titrate to 2-3 soft stools per day. Mechanism: converts NH3 to NH4+ in colon (trapped and excreted). Can be given orally or rectally (retention enema). Rifaximin often added for additional ammonia reduction."),

  // ============================================================
  // RENAL (5)
  // ============================================================
  q("Renal/Urinary", 3, "A nurse is caring for a client with a peritoneal dialysis catheter who develops cloudy effluent, fever, and abdominal pain. The nurse suspects:", ["Normal dialysis findings", "Peritonitis — the most serious complication of peritoneal dialysis", "Dehydration", "Exit site infection only"], 1, "Peritonitis is the most common serious complication of PD. Classic triad: cloudy effluent, abdominal pain, and fever. Diagnosis: WBC count >100/μL in effluent with >50% neutrophils, and positive effluent culture. Treatment: intraperitoneal antibiotics (vancomycin + aminoglycoside or cephalosporin). If recurrent or fungal peritonitis: catheter removal and temporary switch to hemodialysis. Option A is dangerous. Options C and D are different conditions.", "Peritoneal Dialysis", "Peritonitis Recognition", ["renal", "PD", "peritonitis", "complications"], "PD peritonitis: cloudy effluent + abdominal pain + fever. Send effluent for cell count and culture. IP antibiotics. Most common organisms: Staph epidermidis, Staph aureus. Prevention: strict aseptic technique during exchanges, exit site care."),

  q("Renal/Urinary", 2, "A client receiving continuous bladder irrigation (CBI) after a transurethral resection of the prostate (TURP) develops dark red output with clots. The nurse should:", ["Stop the irrigation", "Increase the irrigation rate to flush clots and prevent catheter obstruction; notify the provider if drainage remains dark red", "Clamp the catheter", "Remove the catheter"], 1, "Post-TURP CBI maintains catheter patency by flushing blood clots from the bladder. If drainage becomes dark red or clot-rich: increase the irrigation rate to flush clots. If the catheter becomes blocked: manually irrigate with a syringe per protocol/orders. Continuous bright red output or increasing clot formation may indicate hemorrhage — notify the provider. Option A allows clot formation and retention. Options C and D are contraindicated.", "Post-Surgical Urology", "CBI Management", ["renal", "TURP", "CBI", "post-operative"], "Post-TURP CBI: irrigate at rate to keep drainage pink-tinged. Dark red + clots: increase rate. Catheter obstruction: manual irrigation with 50mL syringe. Complications to watch: hemorrhage, TURP syndrome (hyponatremia from irrigant absorption), bladder spasm."),

  // ============================================================
  // NEURO (5)
  // ============================================================
  q("Neurological", 3, "A client with multiple sclerosis (MS) develops an acute exacerbation. The nurse should anticipate which treatment?", ["Oral aspirin", "High-dose IV methylprednisolone to reduce inflammation and shorten the exacerbation", "Antibiotics", "Immediate surgery"], 1, "MS exacerbations (relapses) are treated with high-dose IV corticosteroids (methylprednisolone 1g IV daily for 3-5 days), which reduce inflammation, shorten exacerbation duration, and speed recovery. Plasmapheresis is an alternative for severe relapses not responding to steroids. Disease-modifying therapies (interferons, glatiramer, fingolimod, ocrelizumab) reduce relapse frequency but are maintenance medications, not for acute treatment. Options A, C, and D are not indicated.", "Multiple Sclerosis", "Acute Exacerbation Treatment", ["neuro", "MS", "methylprednisolone", "exacerbation"], "MS exacerbation: IV methylprednisolone x 3-5 days. Monitor: glucose (steroids), BP, GI symptoms. Disease-modifying therapy for prevention: interferons, glatiramer, natalizumab, ocrelizumab, fingolimod. Monitor for PML with natalizumab."),

  q("Neurological", 2, "A nurse is assessing a client using the Glasgow Coma Scale (GCS). The client opens eyes to pain, makes incomprehensible sounds, and flexes to pain. The GCS score is:", ["15 (normal)", "8 (Eye 2 + Verbal 2 + Motor 4 = 8)", "3 (minimum)", "12"], 1, "GCS scoring: Eye opening: spontaneous=4, to voice=3, to pain=2, none=1. Verbal: oriented=5, confused=4, inappropriate words=3, incomprehensible sounds=2, none=1. Motor: obeys commands=6, localizes pain=5, flexion withdrawal=4, abnormal flexion=3, extension=2, none=1. This client: Eyes to pain=2, incomprehensible sounds=2, flexion to pain=4, total=8. GCS ≤8 indicates need for intubation. Options A, C, and D are incorrect calculations.", "Neurological Assessment", "GCS Scoring", ["neuro", "GCS", "assessment", "LOC"], "GCS: E(4)+V(5)+M(6)=15 max. Score ≤8 = intubate (cannot protect airway). Score 3 = minimum (not 0). Motor is most prognostic component. Document breakdown, not just total (e.g., E2V2M4=8)."),

  // ============================================================
  // ENDOCRINE (5)
  // ============================================================
  q("Endocrine", 3, "A client with pheochromocytoma is scheduled for adrenalectomy. The nurse should anticipate preoperative management with:", ["Immediate surgery without preparation", "Alpha-adrenergic blockers (phenoxybenzamine) for 7-14 days before surgery, then beta-blockers after adequate alpha-blockade", "Beta-blockers first, then alpha-blockers", "No medications are needed preoperatively"], 1, "Pheochromocytoma produces excessive catecholamines causing severe hypertension. Preoperative preparation: alpha-adrenergic blockade FIRST (phenoxybenzamine for 7-14 days to control BP and prevent hypertensive crisis during tumor manipulation). THEN add beta-blockers for tachycardia ONLY after adequate alpha-blockade. Starting beta-blockers first can cause unopposed alpha stimulation and hypertensive crisis. Liberal salt and fluid intake to expand volume. Option C is dangerous (unopposed alpha stimulation). Options A and D risk intraoperative hypertensive crisis.", "Pheochromocytoma", "Preoperative Management", ["endocrine", "pheochromocytoma", "alpha-blockade", "pre-operative"], "Pheochromocytoma prep: ALPHA before BETA (always). Phenoxybenzamine x 7-14 days → add propranolol if tachycardic. Surgery: prepare for blood pressure lability. Post-op: monitor for hypotension and hypoglycemia (catecholamine withdrawal)."),

  q("Endocrine", 3, "A client with SIADH has a serum sodium of 118 mEq/L. The nurse should expect which treatment?", ["Encourage oral fluid intake", "Fluid restriction to 500-1000 mL/day, hypertonic saline for severe cases, and correction of sodium no faster than 8-12 mEq/L per 24 hours", "IV normal saline wide open", "High-sodium diet alone"], 1, "SIADH causes dilutional hyponatremia from excessive ADH and water retention. Treatment: fluid restriction (primary), hypertonic saline (3% NaCl) for severe symptomatic hyponatremia (seizures, coma), demeclocycline or tolvaptan (ADH antagonist) for chronic SIADH. CRITICAL: correct sodium no faster than 8-12 mEq/L per 24 hours to prevent osmotic demyelination syndrome (central pontine myelinolysis). Options A and C worsen hyponatremia. Option D alone is insufficient.", "SIADH", "Hyponatremia Management", ["endocrine", "SIADH", "hyponatremia", "fluid-restriction"], "SIADH correction: max 8-12 mEq/L per 24 hours (osmotic demyelination risk if faster). Severe (Na <120 with seizures): 3% saline. Monitor Na q2-4h during correction. Fluid restrict 500-1000 mL/day. Tolvaptan for refractory cases."),

  // ============================================================
  // HEMATOLOGY/ONCOLOGY (5)
  // ============================================================
  q("Hematology", 3, "A nurse is caring for a client with disseminated intravascular coagulation (DIC). The nurse should understand that DIC involves:", ["Only excessive clotting", "Simultaneous widespread clotting AND bleeding due to consumption of clotting factors and platelets", "Only excessive bleeding", "Normal coagulation with elevated platelet count"], 1, "DIC is a paradoxical condition where widespread microvascular thrombosis simultaneously consumes clotting factors and platelets, leading to hemorrhage. Lab findings: elevated PT/PTT, decreased fibrinogen, decreased platelets, elevated D-dimer and FDPs. Causes: sepsis, trauma, obstetric emergencies, malignancy, transfusion reactions. Treatment: address the underlying cause, replace blood products (FFP, platelets, cryoprecipitate). Options A, C, and D only describe half of the pathology.", "DIC", "Pathophysiology", ["hematology", "DIC", "coagulopathy", "critical-care"], "DIC: clotting AND bleeding simultaneously. Labs: elevated PT/PTT, decreased fibrinogen, decreased platelets, elevated D-dimer. Treatment: TREAT THE CAUSE. Support: FFP (factors), cryoprecipitate (fibrinogen), platelets. Heparin controversial but may be used in thrombosis-predominant DIC."),

  q("Hematology", 2, "A nurse is caring for a client with neutropenia (ANC < 500). Which precaution is most important?", ["Strict bed rest", "Meticulous hand hygiene by all who enter the room, avoiding fresh flowers and raw foods, and monitoring for subtle infection signs", "Restricting all visitors permanently", "Wearing a gown at all times"], 1, "Neutropenic precautions: strict hand hygiene (most important single intervention), private room, avoid fresh flowers/plants (harbor fungi), avoid raw fruits and vegetables (low-microbial diet), no contact with ill persons, avoid rectal temperatures and suppositories, daily assessment for subtle infection signs (neutropenic patients may not mount a fever or show typical inflammation). Option A is unnecessary. Option C is too restrictive (healthy visitors with hand hygiene are acceptable). Option D is not always required.", "Neutropenia", "Protective Precautions", ["hematology", "neutropenia", "infection-prevention", "oncology"], "Neutropenic precautions: ANC <500 = high risk. Fever (>100.4°F/38°C) in neutropenic patient = medical emergency (neutropenic fever). Blood cultures + empiric broad-spectrum antibiotics within 1 hour. Subtle signs may be the only indication of infection."),

  // ============================================================
  // MUSCULOSKELETAL (5)
  // ============================================================
  q("Musculoskeletal", 3, "A nurse is assessing a client who fell and may have a hip fracture. The affected leg appears:", ["Normal in length and alignment", "Shortened, externally rotated, and adducted", "Lengthened and internally rotated", "Flexed at the knee with no other abnormalities"], 1, "Classic hip fracture presentation: the affected leg is shortened (due to muscle spasm pulling the bone fragments together), externally rotated (gravity and muscle forces rotate the leg outward), and adducted (muscles pull the leg inward). The client will report severe groin or hip pain, worsened by movement. An X-ray confirms the diagnosis. Option A shows no fracture. Options C and D are not classic presentations.", "Hip Fracture", "Assessment Findings", ["musculoskeletal", "hip-fracture", "assessment", "trauma"], "Hip fracture presentation: shortened, externally rotated, adducted leg. Severe pain with movement. Complications: DVT, PE, fat embolism, AVN (avascular necrosis of femoral head). Surgery within 24-48 hrs improves outcomes."),

  q("Musculoskeletal", 2, "A client with a new cast reports numbness and tingling in the extremity distal to the cast. The nurse should:", ["Reassure the client this is normal", "Assess neurovascular status immediately — this may indicate compartment syndrome; notify the provider", "Elevate the extremity above the heart", "Wait 24 hours to see if symptoms resolve"], 1, "Numbness and tingling (paresthesia) distal to a cast are early signs of neurovascular compromise, possibly compartment syndrome. The nurse should immediately assess the 5 P's: Pain (out of proportion, pain with passive stretch), Pallor, Pulselessness, Paresthesia, Paralysis (late sign). Notify the provider — the cast may need to be bivalved (cut in half) to relieve pressure. Options A and D delay critical intervention. Option C may help but does not address the urgency.", "Cast Complications", "Neurovascular Assessment", ["musculoskeletal", "cast", "compartment-syndrome", "neurovascular"], "Compartment syndrome 5 P's: Pain (unrelieved by opioids, pain with passive stretch = earliest reliable sign), Paresthesia, Paralysis (late), Pallor, Pulselessness (very late). Treatment: bivalve cast, fasciotomy if compartment syndrome confirmed. Irreversible damage in 4-6 hours."),

  // ============================================================
  // IMMUNOLOGY (5)
  // ============================================================
  q("Immunological", 3, "A client with HIV asks about the difference between HIV and AIDS. The nurse should explain:", ["They are the same condition", "HIV is the virus that attacks CD4+ T-cells; AIDS is diagnosed when CD4+ count drops below 200 cells/mm3 or an AIDS-defining illness occurs", "AIDS always develops within 1 year of HIV infection", "HIV is curable with current medications"], 1, "HIV (human immunodeficiency virus) attacks CD4+ T-lymphocytes, progressively weakening the immune system. AIDS (acquired immunodeficiency syndrome) is the most advanced stage, defined by CD4+ <200 cells/mm3 (normal 500-1500) OR the presence of an AIDS-defining opportunistic infection (PJP, KS, CMV retinitis, etc.). With ART (antiretroviral therapy), many HIV-positive individuals never progress to AIDS. Options A and C are incorrect. Option D — HIV is treatable but not yet curable.", "HIV/AIDS", "Disease Progression", ["immunology", "HIV", "AIDS", "CD4"], "HIV to AIDS: CD4 <200 or AIDS-defining illness. ART can maintain viral suppression indefinitely. U=U (Undetectable = Untransmittable). Normal CD4: 500-1500. Start ART at diagnosis regardless of CD4 count."),

  q("Immunological", 2, "A nurse is educating a client about lupus (SLE). The nurse should teach that the most important trigger to avoid is:", ["Cold temperatures", "Prolonged sun exposure, which can trigger disease flares", "High-protein foods", "Exercise"], 1, "SLE is an autoimmune disease with photosensitivity as a hallmark feature. UV light exposure (sunlight, tanning beds) can trigger disease flares including the characteristic butterfly (malar) rash, joint pain, fatigue, and potentially organ involvement (lupus nephritis, serositis). Teaching: avoid sun exposure, use SPF 50+ broad-spectrum sunscreen, wear protective clothing and wide-brimmed hats, and schedule outdoor activities for early morning or evening. Options A, C, and D are not primary triggers.", "Systemic Lupus", "Photosensitivity", ["immunology", "lupus", "SLE", "photosensitivity"], "SLE photosensitivity: UV triggers flares. SPF 50+ daily, protective clothing, avoid midday sun. Other triggers: stress, infection, certain medications (hydralazine, procainamide, isoniazid can cause drug-induced lupus). Monitor: anti-dsDNA, complement levels, renal function."),

  // ============================================================
  // PHARMACOLOGY FINAL SET (37)
  // ============================================================
  q("Pharmacology", 3, "A client is receiving IV potassium chloride replacement. The nurse should ensure:", ["The KCl is administered by IV push for rapid correction", "KCl is diluted and infused via pump at no more than 10-20 mEq/hour through a central or large peripheral vein; NEVER give IV push", "KCl can be infused at any rate", "KCl can be added to D5W only"], 1, "IV KCl safety: NEVER give IV push (can cause fatal cardiac arrest). Maximum rate: 10-20 mEq/hour (10 mEq/hr through peripheral line, up to 20 mEq/hr through central line with cardiac monitoring). Maximum concentration: 40 mEq/L through peripheral line (higher concentrations cause phlebitis). Always use an infusion pump. Cardiac monitoring for rates >10 mEq/hr. Option A is lethal. Options C and D are incorrect.", "Electrolyte Replacement", "IV KCl Safety", ["pharmacology", "potassium", "IV-safety", "medication-administration"], "IV KCl: NEVER push (fatal cardiac arrest). Max peripheral rate: 10 mEq/hr. Central line: up to 20 mEq/hr with cardiac monitoring. Max peripheral concentration: 40 mEq/L. Always use pump. Monitor ECG for peaked T waves during rapid correction."),

  q("Pharmacology", 3, "A client is prescribed spironolactone for heart failure. The nurse should teach:", ["This medication has no hormonal effects", "Men may experience gynecomastia (breast enlargement) and women may have menstrual irregularities; monitor potassium levels", "Take with potassium supplements", "This medication causes hypokalemia"], 1, "Spironolactone is an aldosterone antagonist that blocks aldosterone-mediated sodium reabsorption and potassium excretion. It also has anti-androgenic effects: gynecomastia and breast tenderness in men, menstrual irregularities in women. Alternative: eplerenone (more selective, fewer hormonal effects). Monitor serum potassium closely (hyperkalemia risk). Avoid potassium supplements and K-rich foods. Options A, C, and D are incorrect.", "Heart Failure Medications", "Spironolactone Side Effects", ["pharmacology", "spironolactone", "gynecomastia", "hyperkalemia"], "Spironolactone: part of HFrEF GDMT (mortality benefit). Anti-androgenic effects: gynecomastia (switch to eplerenone if problematic). Monitor K+ closely — avoid K+ supplements, ACE-I/ARB + spironolactone = high hyperkalemia risk."),

  q("Pharmacology", 3, "A client is receiving vancomycin IV. The nurse infuses it too rapidly and the client develops flushing of the face, neck, and upper trunk. This reaction is called:", ["Anaphylaxis", "Red man syndrome — caused by histamine release from rapid infusion, not a true allergy", "Serum sickness", "Drug-induced lupus"], 1, "Red man syndrome (RMS) is a histamine-mediated reaction to rapid vancomycin infusion, NOT a true allergic reaction. Signs: flushing, erythema, pruritus of the face, neck, and upper trunk. Prevention: infuse vancomycin over at least 60 minutes (or 1g per hour). Treatment: stop infusion, administer antihistamines (diphenhydramine), then resume at a slower rate. RMS does NOT contraindicate future vancomycin use. Options A, C, and D are different reactions.", "Antibiotics", "Red Man Syndrome", ["pharmacology", "vancomycin", "red-man-syndrome", "infusion-reaction"], "Red man syndrome: NOT true allergy (histamine release from rapid infusion). Infuse vancomycin ≥60 min. If RMS occurs: stop, give diphenhydramine, resume slowly. Can still use vancomycin in the future. True vancomycin allergy is rare but possible."),

  q("Pharmacology", 2, "A client is prescribed prochlorperazine (Compazine) for nausea. The nurse should monitor for:", ["Hyperglycemia", "Extrapyramidal symptoms including dystonia, akathisia, and tardive dyskinesia", "Hypertension", "Tachycardia"], 1, "Prochlorperazine is a phenothiazine antiemetic that blocks dopamine receptors. Like all dopamine antagonists, it can cause extrapyramidal symptoms (EPS): acute dystonia (muscle spasm, torticollis), akathisia (restlessness), parkinsonian symptoms (rigidity, bradykinesia), and tardive dyskinesia (involuntary movements with long-term use). Treatment for acute dystonia: diphenhydramine or benztropine. Options A, C, and D are not primary concerns.", "Antiemetics", "Prochlorperazine EPS", ["pharmacology", "prochlorperazine", "EPS", "antiemetic"], "Phenothiazine antiemetics: EPS risk (treat acute dystonia with diphenhydramine/benztropine). Also: sedation, orthostatic hypotension, photosensitivity. Alternative antiemetics with less EPS risk: ondansetron, promethazine (still some EPS risk)."),

  q("Pharmacology", 3, "A client is prescribed fondaparinux (Arixtra) for DVT prophylaxis. The nurse should know that unlike heparin:", ["Fondaparinux can be reversed with protamine sulfate", "Fondaparinux has no reliable reversal agent and carries a lower risk of HIT (heparin-induced thrombocytopenia)", "Fondaparinux requires aPTT monitoring", "Fondaparinux can be given IV push"], 1, "Fondaparinux is a synthetic factor Xa inhibitor administered SC once daily. Advantages: lower HIT risk (does not bind platelet factor 4), no need for routine monitoring, SC administration. Disadvantages: no specific reversal agent (protamine is ineffective), renal clearance (contraindicated with CrCl <30 mL/min). Options A, C, and D are incorrect about fondaparinux.", "Anticoagulant Therapy", "Fondaparinux Characteristics", ["pharmacology", "fondaparinux", "DVT-prophylaxis", "no-reversal"], "Fondaparinux: SC daily, no routine monitoring, very low HIT risk. NO reversal agent (recombinant factor VIIa may be attempted in emergencies). Renal clearance — adjust/avoid in CKD. Monitor anti-Xa levels only if needed (obesity, renal impairment)."),

  q("Pharmacology", 3, "A nurse is preparing to administer medications to a client with a jejunostomy tube. The nurse should:", ["Administer all medications in their regular oral forms", "Use liquid formulations when available, dilute properly, flush with water, and verify that the medication is appropriate for jejunal delivery (some medications require gastric acid)", "Crush enteric-coated tablets for administration", "Mix all medications together"], 1, "Jejunostomy tube medication considerations: the jejunum lacks gastric acid, so medications requiring acidic pH for activation or absorption may be ineffective (e.g., ketoconazole, iron sulfate, enteric-coated medications). Use liquid formulations when possible, dilute hypertonic solutions (prevent osmotic diarrhea), flush with 15-30 mL water, and verify jejunal appropriateness with pharmacy. Option A ignores absorption differences. Option C destroys enteric coating (and may not work in the jejunum anyway). Option D risks interactions.", "Enteral Medication", "Jejunostomy Administration", ["pharmacology", "jejunostomy", "tube-feeding", "medication-delivery"], "Jejunostomy medications: no gastric acid = some drugs ineffective. Consult pharmacy for alternatives. Liquid preferred. Dilute hypertonic solutions. No enteric-coated meds. Hold tube feeding for phenytoin (binding reduces absorption by 70%)."),

  q("Pharmacology", 3, "A client with acute gout is prescribed indomethacin. The nurse should advise:", ["Take on an empty stomach", "Take with food to reduce GI irritation; monitor for renal function changes and GI bleeding", "This medication has no GI side effects", "Take with grapefruit juice"], 1, "Indomethacin is a potent NSAID used for acute gout due to its strong anti-inflammatory properties. GI side effects are significant: nausea, abdominal pain, GI bleeding, and ulceration. Take with food or antacids. Also monitor: renal function (can worsen kidney disease), blood pressure (fluid retention), and bleeding (especially if on anticoagulants). Contraindicated in renal impairment and active peptic ulcer disease. Options A, C, and D are incorrect.", "NSAIDs", "Indomethacin Education", ["pharmacology", "indomethacin", "NSAID", "gout"], "NSAID risks: GI bleeding, renal impairment, cardiovascular events (all NSAIDs carry some CV risk), platelet dysfunction. Take with food. Avoid in CKD, active GI bleeding, third trimester pregnancy. PPI co-prescription for high-risk patients."),

  q("Pharmacology", 3, "A nurse is monitoring a client on a lithium-containing regimen for bipolar disorder. Which electrolyte imbalance increases lithium toxicity risk?", ["Hyperkalemia", "Hyponatremia — sodium depletion causes increased lithium reabsorption in the kidneys", "Hypermagnesemia", "Hypercalcemia"], 1, "Lithium and sodium are reabsorbed by the same renal proximal tubule transporters. When sodium is low (hyponatremia), the kidneys compensate by reabsorbing more sodium — and lithium along with it — leading to lithium accumulation and toxicity. Causes of hyponatremia in lithium patients: dehydration, diuretics (thiazides are especially dangerous), excessive sweating, low-sodium diets, and vomiting/diarrhea. Options A, C, and D do not have this relationship.", "Mood Stabilizers", "Lithium-Sodium Relationship", ["pharmacology", "lithium", "hyponatremia", "toxicity"], "Lithium + sodium: inverse relationship. Low Na = high lithium. Maintain consistent sodium intake. Avoid thiazide diuretics (increase lithium levels). Stay hydrated (2-3 L/day). Therapeutic level: 0.6-1.2 mEq/L. Toxicity: >1.5 mEq/L."),

  q("Pharmacology", 2, "A client prescribed warfarin asks about over-the-counter pain relievers. The nurse should advise:", ["NSAIDs are the safest choice", "Use acetaminophen for pain relief; avoid NSAIDs and aspirin as they increase bleeding risk when combined with warfarin", "Any pain reliever is safe with warfarin", "Only use ibuprofen"], 1, "NSAIDs (ibuprofen, naproxen) and aspirin increase bleeding risk when combined with warfarin through multiple mechanisms: GI irritation, platelet inhibition, and displacement of warfarin from protein-binding sites. Acetaminophen at appropriate doses (<2g/day for warfarin patients) is the safest OTC analgesic. High-dose acetaminophen can increase INR. Options A, C, and D increase bleeding risk.", "Anticoagulant Therapy", "OTC Pain Relief Safety", ["pharmacology", "warfarin", "NSAIDs", "pain-management"], "Warfarin + pain: acetaminophen first-line (limit 2g/day — high doses increase INR). Avoid NSAIDs (GI bleeding + platelet inhibition + protein displacement). If NSAID needed: shortest duration, lowest dose, add PPI, monitor INR more frequently."),

  q("Pharmacology", 3, "A client is started on an MAOI (phenelzine) for depression. The nurse must teach about the most dangerous food interaction:", ["Avoiding all fruits", "Avoiding tyramine-rich foods (aged cheese, cured meats, draft beer, soy sauce, fermented foods) to prevent hypertensive crisis", "Avoiding vitamin C-rich foods", "Avoiding all carbohydrates"], 1, "MAOIs prevent the breakdown of tyramine in the GI tract. Tyramine-rich foods cause massive norepinephrine release, leading to potentially fatal hypertensive crisis (severe headache, stiff neck, nausea, palpitations, stroke). High-tyramine foods: aged cheeses, cured/smoked meats, fermented foods, soy sauce, draft beer, sauerkraut, broad beans. Dietary restrictions continue for 2 weeks after stopping the MAOI. Options A, C, and D are incorrect restrictions.", "MAO Inhibitors", "Tyramine Interaction", ["pharmacology", "MAOI", "tyramine", "hypertensive-crisis"], "MAOI + tyramine = hypertensive crisis. Dietary restrictions for 14 days after stopping MAOI. Also avoid: sympathomimetics (pseudoephedrine), meperidine, SSRIs (serotonin syndrome). Treatment of crisis: phentolamine IV (alpha-blocker)."),

  q("Pharmacology", 2, "A nurse is teaching a client about the proper use of a metered-dose inhaler (MDI). The correct technique includes:", ["Inhale quickly and forcefully", "Shake the inhaler, exhale completely, place mouthpiece in mouth, press the canister while inhaling slowly and deeply, hold breath for 10 seconds", "Exhale into the inhaler before pressing the canister", "Breathe normally during activation"], 1, "MDI technique: 1) Shake the canister, 2) Exhale completely, 3) Place mouthpiece in mouth (or 1-2 inches from open mouth), 4) Press canister while inhaling SLOWLY and DEEPLY, 5) Hold breath for 10 seconds, 6) Wait 1 minute between puffs. Use a spacer to improve medication delivery (especially with ICS). Clean mouthpiece regularly. Option A delivers medication to the throat. Option C wastes medication. Option D reduces lung deposition.", "Inhalers", "MDI Technique", ["pharmacology", "MDI", "inhaler-technique", "patient-education"], "MDI: slow deep breath. DPI: quick deep breath. Key difference! Spacer improves MDI delivery by 80% (essential for children and ICS). Prime new MDI with 4 test sprays. Track doses to avoid using empty inhaler."),

  q("Pharmacology", 3, "A client with opioid-induced constipation is prescribed methylnaltrexone (Relistor). The nurse should explain:", ["This medication will cause respiratory depression", "This is a peripheral opioid receptor antagonist that reverses constipation without affecting central pain relief", "This will block the analgesic effect of opioids", "This medication treats all types of constipation"], 1, "Methylnaltrexone (and naloxegol) are peripheral-acting mu-opioid receptor antagonists (PAMORAs). They block opioid receptors in the GI tract, reversing opioid-induced constipation, WITHOUT crossing the blood-brain barrier — therefore, they do NOT reverse analgesia, sedation, or cause withdrawal. SC injection (methylnaltrexone) or oral (naloxegol). Options A and C describe central opioid antagonists (naloxone). Option D is incorrect — only for opioid-induced constipation.", "Opioid Side Effect Management", "Peripheral Opioid Antagonist", ["pharmacology", "methylnaltrexone", "opioid-constipation", "PAMORA"], "PAMORAs: peripheral mu-antagonists (do NOT affect analgesia). Methylnaltrexone (SC), naloxegol (PO), naldemedine (PO). For opioid-induced constipation that does not respond to conventional laxatives. Effect: bowel movement usually within 30-60 min of SC dose."),

  q("Pharmacology", 3, "A nurse is preparing to administer alteplase (tPA) for acute ischemic stroke. The medication must be given within:", ["24 hours of symptom onset", "4.5 hours of symptom onset (or last known well time)", "12 hours of symptom onset", "No time limit applies"], 1, "IV alteplase for acute ischemic stroke has a treatment window of up to 4.5 hours from symptom onset or the time the patient was last known to be neurologically normal. Earlier treatment yields better outcomes (time is brain — 1.9 million neurons lost per minute). Extended window (6-24 hours) may apply for mechanical thrombectomy in select patients with large vessel occlusion based on perfusion imaging. Options A, C, and D are incorrect for IV tPA.", "Thrombolytic Therapy", "Treatment Window", ["pharmacology", "tPA", "stroke", "time-window"], "Stroke tPA: 4.5-hour window. Door-to-needle time goal: <60 minutes. Dose: 0.9 mg/kg (max 90 mg), 10% as bolus over 1 min, remainder over 60 min. Mechanical thrombectomy: up to 24 hrs for large vessel occlusion with favorable imaging."),

  q("Pharmacology", 2, "A client asks why daily aspirin was prescribed after a coronary stent. The nurse explains:", ["Aspirin prevents infection at the stent site", "Aspirin inhibits platelet aggregation, preventing blood clots from forming inside the stent (stent thrombosis)", "Aspirin reduces cholesterol", "Aspirin is given for its pain-relieving properties"], 1, "After coronary stenting, the stent surface is thrombogenic until endothelialization occurs. Aspirin irreversibly inhibits cyclooxygenase (COX), blocking thromboxane A2 production and preventing platelet aggregation. Combined with a P2Y12 inhibitor (clopidogrel, ticagrelor, or prasugrel) as dual antiplatelet therapy (DAPT), this prevents stent thrombosis, which has 20-40% mortality. Options A, C, and D are not the primary reason.", "Antiplatelet Therapy", "Post-Stent Aspirin", ["pharmacology", "aspirin", "stent", "antiplatelet"], "Post-stent DAPT: aspirin (lifelong) + P2Y12 inhibitor (typically 12 months for DES, minimum 1 month for BMS). Premature discontinuation = #1 risk factor for stent thrombosis. Educate: never stop without cardiology approval."),

  q("Pharmacology", 3, "A client is prescribed rifampin for tuberculosis. The nurse should teach:", ["No drug interactions exist", "Rifampin turns body fluids orange-red and is a potent enzyme inducer that reduces effectiveness of many medications", "Take on an empty stomach with milk", "This medication works within 24 hours"], 1, "Rifampin teaching: body fluids (urine, tears, sweat, saliva) will turn orange-red (expected, not harmful — warn about stained contact lenses and clothing). Rifampin is one of the most potent CYP450 inducers, reducing levels of: oral contraceptives, warfarin, HIV antiretrovirals, antifungals, and many other drugs. TB treatment requires multi-drug therapy for 6-9 months. Option A is dangerously wrong. Option C — take on empty stomach with water. Option D — TB treatment is months-long.", "Antitubercular Agents", "Rifampin Education", ["pharmacology", "rifampin", "TB", "enzyme-induction"], "Rifampin: orange body fluids (warn about contacts), potent enzyme inducer (check ALL drug interactions). TB regimen: RIPE (Rifampin, Isoniazid, Pyrazinamide, Ethambutol) x 2 months, then RI x 4 months. Monitor LFTs (hepatotoxic)."),

  q("Pharmacology", 3, "A client is receiving continuous IV nitroglycerin. The nurse should monitor for:", ["Hyperglycemia", "Headache, hypotension, and tachycardia; measure blood pressure frequently and titrate to target", "Hypertension", "Hyperkalemia"], 1, "IV nitroglycerin causes vasodilation (primarily venous, reducing preload; at higher doses, arterial dilation reducing afterload). Side effects: headache (most common), hypotension (dose-dependent), reflex tachycardia, and flushing. Monitor BP continuously (arterial line preferred for titration). Administer via non-PVC tubing (PVC absorbs nitroglycerin). Options A, C, and D are not nitroglycerin effects.", "Antianginal Agents", "IV NTG Monitoring", ["pharmacology", "nitroglycerin", "IV-infusion", "hemodynamic-monitoring"], "IV nitroglycerin: non-PVC tubing (PVC absorbs drug). Glass bottle preferred. Titrate to BP and symptom response. Headache = expected (treat with acetaminophen). Tolerance develops with continuous infusion — use nitrate-free intervals when possible."),

  q("Pharmacology", 2, "A client is prescribed allopurinol for chronic gout prophylaxis. The nurse should teach:", ["Start during an acute gout attack for immediate relief", "Do NOT start during an acute attack; this medication prevents future attacks by lowering uric acid and may take weeks to reach full effect", "Take only when experiencing joint pain", "This medication treats acute gout pain"], 1, "Allopurinol is a xanthine oxidase inhibitor that reduces uric acid production. It is used for chronic gout PROPHYLAXIS, NOT acute treatment. Starting allopurinol during an acute attack can paradoxically worsen and prolong the flare (uric acid mobilization). Start 2-4 weeks after acute attack resolves, at a low dose with gradual titration. Colchicine is often co-prescribed during initiation to prevent flares. Options A, C, and D are incorrect uses.", "Uric Acid Lowering", "Allopurinol Education", ["pharmacology", "allopurinol", "gout", "uric-acid"], "Allopurinol: do NOT start during acute attack. Start low, go slow (100 mg/day, increase q2-4 weeks). Target uric acid <6 mg/dL. Colchicine prophylaxis during initiation (3-6 months). Monitor: LFTs, CBC. Hypersensitivity syndrome (rare but fatal)."),

  q("Pharmacology", 3, "A client is prescribed liraglutide (Victoza). The nurse should assess for which rare but serious adverse effect?", ["Hypothyroidism", "Acute pancreatitis — report severe persistent abdominal pain radiating to the back", "Hypoglycemia as a primary effect", "Hepatotoxicity"], 1, "GLP-1 receptor agonists carry a risk of acute pancreatitis. Symptoms: severe, persistent abdominal pain (often radiating to the back), nausea, vomiting, and elevated lipase/amylase. Discontinue immediately if pancreatitis is suspected. Also: black box warning for thyroid C-cell tumors. Option A — thyroid C-cell tumors, not hypothyroidism. Option C — hypoglycemia is rare as monotherapy (glucose-dependent action). Option D is not the primary serious effect.", "GLP-1 Receptor Agonists", "Pancreatitis Risk", ["pharmacology", "liraglutide", "GLP-1", "pancreatitis"], "GLP-1 RA serious risks: pancreatitis (stop immediately if suspected), thyroid C-cell tumors (black box), gallbladder disease. Benefits: weight loss, A1C reduction, cardiovascular protection (liraglutide, semaglutide). GI side effects (nausea) most common."),

  q("Pharmacology", 3, "A nurse is teaching a client about theophylline for COPD. Which beverage should the client limit?", ["Water", "Caffeinated beverages, as caffeine is structurally similar to theophylline and can enhance side effects", "Decaffeinated tea", "Milk"], 1, "Theophylline and caffeine are both methylxanthines with similar pharmacological effects (bronchodilation, CNS stimulation, cardiac stimulation, diuresis). Excessive caffeine consumption enhances theophylline's side effects: tachycardia, tremor, restlessness, insomnia, and potentially seizures. Clients should limit caffeine intake and avoid large amounts of coffee, tea, cola, and chocolate. Options A, C, and D do not significantly interact with theophylline.", "Methylxanthines", "Caffeine Interaction", ["pharmacology", "theophylline", "caffeine", "drug-food-interaction"], "Theophylline + caffeine: both methylxanthines. Limit caffeine. Therapeutic range: 10-20 mcg/mL (narrow). Many drug interactions. Smoking decreases levels (enzyme induction). Stopping smoking increases levels (need dose reduction)."),
];

async function main() {
  let inserted = 0;
  const batchSize = 50;
  for (let i = 0; i < QS.length; i += batchSize) {
    const batch = QS.slice(i, i + batchSize);
    const values: string[] = [];
    const params: any[] = [];
    let idx = 1;
    for (const item of batch) {
      values.push(`($${idx},$${idx+1},$${idx+2},$${idx+3},$${idx+4},$${idx+5}::jsonb,$${idx+6}::jsonb,$${idx+7},$${idx+8}::integer,$${idx+9},$${idx+10},$${idx+11},$${idx+12},$${idx+13},$${idx+14}::text[],$${idx+15})`);
      params.push(
        item.tier, item.exam, "multiple_choice", "published",
        item.stem, JSON.stringify(item.options), JSON.stringify([item.correct]),
        item.rationale, item.diff, item.bs, "BOTH", hash(item.stem),
        item.topic, item.subtopic, "{" + item.tags.join(",") + "}", item.clinicalPearl
      );
      idx += 16;
    }
    const sql = `INSERT INTO exam_questions (tier, exam, question_type, status, stem, options, correct_answer, rationale, difficulty, body_system, region_scope, stem_hash, topic, subtopic, tags, clinical_pearl)
                 SELECT v.* FROM (VALUES ${values.join(",")}) AS v(tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash,topic,subtopic,tags,clinical_pearl)
                 WHERE NOT EXISTS (SELECT 1 FROM exam_questions e WHERE e.stem_hash = v.stem_hash)`;
    const result = await pool.query(sql, params);
    inserted += result.rowCount || 0;
    console.log(`[RN-MedSurg-Pharm-B6] Batch ${Math.floor(i/batchSize)+1}: inserted ${result.rowCount || 0} questions`);
  }
  console.log(`\n[RN-MedSurg-Pharm-B6] Total inserted: ${inserted}/${QS.length}`);
  const counts = await pool.query(`SELECT tier, count(*) as cnt FROM exam_questions WHERE status='published' GROUP BY tier ORDER BY tier`);
  counts.rows.forEach((r: any) => console.log(`  ${r.tier}: ${r.cnt}`));

  const bodySys = await pool.query(`SELECT body_system, count(*) as cnt FROM exam_questions WHERE tier='rn' AND status='published' GROUP BY body_system ORDER BY cnt DESC LIMIT 30`);
  console.log(`\nRN Body System Distribution:`);
  bodySys.rows.forEach((r: any) => console.log(`  ${r.body_system || '(null)'}: ${r.cnt}`));

  const total = await pool.query(`SELECT count(*) as cnt FROM exam_questions WHERE tier='rn' AND status='published'`);
  console.log(`\nTotal RN published questions: ${total.rows[0].cnt}`);

  await pool.end();
}

main().catch(e => { console.error(e); process.exit(1); });
